// 三载体一致:纯 JS 产字节,零 DOM/style/event 足迹
import { PDFDocument, rgb, StandardFonts } from 'https://cdn.jsdelivr.net/npm/pdf-lib@1.17.1/+esm';
let doc;
if (data.existingPdf) {
  const bytes = typeof data.existingPdf === 'string'
    ? Uint8Array.from(atob(data.existingPdf), c => c.charCodeAt(0))
    : data.existingPdf;
  doc = await PDFDocument.load(bytes);
  if (data.formFields) {
    const form = doc.getForm();
    for (const [k, v] of Object.entries(data.formFields)) form.getTextField(k).setText(String(v));
    if (data.flatten) form.flatten();
  }
} else {
  doc = await PDFDocument.create();
  doc.addPage();
}
if (data.draws) {
  const font = await doc.embedFont(StandardFonts.Helvetica);
  for (const d of data.draws) {
    const p = doc.getPage(d.page ?? 0);
    const [r, g, b] = d.color ?? [0, 0, 0];
    p.drawText(d.text, { x: d.x, y: d.y, size: d.size ?? 24, font, color: rgb(r, g, b) });
  }
}
const pdfBytes = await doc.save();
const blob = new Blob([pdfBytes], { type: 'application/pdf' });
